import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import api from "../../api/axios";
import { addSale } from "../../api/saleApi";

export default function AddSale() {
  const navigate = useNavigate();
  const [vehicles, setVehicles] = useState([]);

  const [form, setForm] = useState({
    vehicle: "",
    dealStatus: "initiated",
    paymentStatus: "pending",
    quotedPrice: "",
    finalPrice: "",
    paidAmount: 0,
    paymentMethod: "cash",
    notes: "",
  });

  useEffect(() => {
    api.get("/vehicles")
      .then((res) => {
        // show vehicles not sold (optional)
        setVehicles(res.data.filter((v) => v.status !== "sold"));
      })
      .catch(() => {});
  }, []);

  const submit = async (e) => {
    e.preventDefault();
    try {
      await addSale({
        ...form,
        quotedPrice: form.quotedPrice ? Number(form.quotedPrice) : undefined,
        finalPrice: form.finalPrice ? Number(form.finalPrice) : undefined,
        paidAmount: Number(form.paidAmount || 0),
      });

      alert("Sale recorded!");
      navigate("/sales");
    } catch (err) {
      alert(err.response?.data?.message || "Create failed");
    }
  };

  return (
    <div style={{ padding: 20, maxWidth: 560 }}>
      <h2>Add Sale</h2>

      <form onSubmit={submit}>
        <label>Vehicle</label><br />
        <select
          value={form.vehicle}
          onChange={(e) => setForm({ ...form, vehicle: e.target.value })}
          required
          style={{ width: "100%", padding: 10 }}
        >
          <option value="">Select vehicle</option>
          {vehicles.map((v) => (
            <option key={v._id} value={v._id}>
              {v.brand} {v.model || v.type || ""} ({v.year}) - {v.status}
            </option>
          ))}
        </select>

        <br /><br />

        <label>Deal Status</label><br />
        <select
          value={form.dealStatus}
          onChange={(e) => setForm({ ...form, dealStatus: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="initiated">Initiated</option>
          <option value="completed">Completed</option>
          <option value="cancelled">Cancelled</option>
        </select>

        <br /><br />

        <label>Payment Status</label><br />
        <select
          value={form.paymentStatus}
          onChange={(e) => setForm({ ...form, paymentStatus: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="pending">Pending</option>
          <option value="partial">Partial</option>
          <option value="paid">Paid</option>
          <option value="refunded">Refunded</option>
        </select>

        <br /><br />

        <label>Quoted Price</label><br />
        <input
          type="number"
          value={form.quotedPrice}
          onChange={(e) => setForm({ ...form, quotedPrice: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Final Price</label><br />
        <input
          type="number"
          value={form.finalPrice}
          onChange={(e) => setForm({ ...form, finalPrice: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Paid Amount</label><br />
        <input
          type="number"
          value={form.paidAmount}
          onChange={(e) => setForm({ ...form, paidAmount: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />

        <label>Payment Method</label><br />
        <select
          value={form.paymentMethod}
          onChange={(e) => setForm({ ...form, paymentMethod: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        >
          <option value="cash">Cash</option>
          <option value="bank_transfer">Bank Transfer</option>
          <option value="card">Card</option>
          <option value="cheque">Cheque</option>
          <option value="other">Other</option>
        </select>

        <br /><br />

        <label>Notes</label><br />
        <textarea
          rows={3}
          value={form.notes}
          onChange={(e) => setForm({ ...form, notes: e.target.value })}
          style={{ width: "100%", padding: 10 }}
        />

        <br /><br />
        <button style={{ padding: "10px 14px" }}>Save</button>
      </form>
    </div>
  );
}
